func SqlServerCaptureTableReplicationAttributes() map[string]schema.Attribute {
	return map[string]schema.Attribute{
		"cdc_max_scans": schema.Int32Attribute{
			MarkdownDescription: "Maximum number of scan cycles per polling interval for CDC",
			Optional:            true,
			Computed:            true,
			Default:             int32default.StaticInt32(0),
		},
		"cdc_max_trans": schema.Int32Attribute{
			MarkdownDescription: "Maximum number of transactions to process in a single polling cycle for CDC",
			Optional:            true,
			Computed:            true,
			Default:             int32default.StaticInt32(0),
		},
		"cdc_poll_interval_secs": schema.Int64Attribute{
			MarkdownDescription: "Polling interval in seconds to check for new CDC changes",
			Optional:            true,
			Computed:            true,
			Default:             int64default.StaticInt64(0),
		},
		"skip_snapshot": schema.BoolAttribute{
			MarkdownDescription: "Skip the initial snapshot and start CDC from the current max LSN",
			Optional:            true,
			Computed:            true,
			Default:             booldefault.StaticBool(false),
		},
		"skip_tables_without_ct": schema.BoolAttribute{
			MarkdownDescription: "Skip syncing tables without CDC capture instances instead of failing",
			Optional:            true,
			Computed:            true,
			Default:             booldefault.StaticBool(false),
		},
		"transactional_cdc_enabled": schema.BoolAttribute{
			MarkdownDescription: "Enable transactionally consistent CDC processing",
			Optional:            true,
			Computed:            true,
			Default:             booldefault.StaticBool(false),
		},
	}
}

